diff --git a/llvm/lib/Transforms/Utils/Local.cpp b/llvm/lib/Transforms/Utils/Local.cpp
index e812c00936097..f2f3e63aaa309 100644
--- a/llvm/lib/Transforms/Utils/Local.cpp
+++ b/llvm/lib/Transforms/Utils/Local.cpp
@@ -3172,6 +3172,7 @@ void llvm::copyMetadataForLoad(LoadInst &Dest, const LoadInst &Source) {
     case LLVMContext::MD_access_group:
     case LLVMContext::MD_noundef:
     case LLVMContext::MD_noalias_addrspace:
+    case LLVMContext::MD_invariant_group:
       // All of these directly apply.
       Dest.setMetadata(ID, N);
       break;

tests.test_body:
define i1 @icmp_null_launder_bitcasts(ptr %a) {
  %a3 = call ptr @llvm.launder.invariant.group.p0(ptr %a)
  %r = icmp eq ptr %a3, null
  ret i1 %r
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(inaccessiblemem: readwrite)
declare ptr @llvm.launder.invariant.group.p0(ptr) #0

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(inaccessiblemem: readwrite) }

define i32 @retype_keeps_invariant_group(ptr %p) {
  %v = load float, ptr %p, align 4, !invariant.group !0
  %i = bitcast float %v to i32
  ret i32 %i
}

!0 = !{}
